ops.replace_with:
window.handleBack = () => {
    // 1. Close Overview if active
    if (isOverview) {
        exitOverview();
        return true;
    }
    // 2. Close context menu if open
    const menu = document.getElementById('context-menu');
    if (menu && menu.style.display === 'flex') {
        closeMenu();
        return true;
    }
    // 3. Close app drawer if open
    if (document.body.classList.contains('drawer-active')) {
        showHomeScreen();
        return true;
    }
    return false;
};

function enterOverview() {
    isOverview = true;
    document.body.classList.add('overview-active');
    renderHomeDots();
}

function exitOverview() {
    if (!isOverview) return;
    isOverview = false;
    document.body.classList.remove('overview-active');
}

function renderHomeDots() {
    const container = document.getElementById('home-dots');
    const pageCount = document.querySelectorAll('.home-page').length;
    container.innerHTML = '';
    for(let i=0; i<pageCount; i++) {
        const dot = document.createElement('div');
        dot.className = 'dot' + (i === 0 ? ' active' : '');
        container.appendChild(dot);
    }
}

function updateHomeDots() {
    const pager = document.getElementById('home-pager');
    const dots = document.querySelectorAll('#home-dots .dot');
    const idx = Math.round(pager.scrollLeft / window.innerWidth);
    dots.forEach((d, i) => d.classList.toggle('active', i === idx));
}

